import React, { useEffect, useState } from "react";
import API from "../../api/api";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, PieChart, Pie, Cell, Legend
} from "recharts";

const COLORS = ["#0f766e", "#3b82f6", "#f59e0b", "#ef4444"];

const Reports = () => {
  const [stats, setStats]   = useState({ users: 0, projects: 0, proposals: 0, freelancers: 0, clients: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError]   = useState("");

  useEffect(() => {
    const load = async () => {
      try {
        // ✅ Direct API call — no helper function
        const res = await API.get("/admin/dashboard");
        console.log("Admin dashboard response:", res.data); // debug
        setStats(res.data || {});
      } catch (err) {
        console.error("Reports API error:", err);
        setError("Failed to load stats. Check if backend is running.");
      }
      setLoading(false);
    };
    load();
  }, []);

  const barData = [
    { name: "Users",     value: stats.users     || 0 },
    { name: "Freelancers",value: stats.freelancers|| 0 },
    { name: "Clients",   value: stats.clients    || 0 },
    { name: "Projects",  value: stats.projects   || 0 },
    { name: "Proposals", value: stats.proposals  || 0 },
  ];

  const pieData = [
    { name: "Freelancers", value: stats.freelancers || 0 },
    { name: "Clients",     value: stats.clients     || 0 },
  ].filter(d => d.value > 0);

  const statCards = [
    { label: "Total Users",     value: stats.users      || 0, color: "text-teal-600",   border: "border-teal-500",   icon: "👥" },
    { label: "Total Projects",  value: stats.projects   || 0, color: "text-yellow-600", border: "border-yellow-500", icon: "📁" },
    { label: "Total Proposals", value: stats.proposals  || 0, color: "text-orange-500", border: "border-orange-500", icon: "📄" },
    { label: "Freelancers",     value: stats.freelancers|| 0, color: "text-blue-600",   border: "border-blue-500",   icon: "💻" },
    { label: "Clients",         value: stats.clients    || 0, color: "text-purple-600", border: "border-purple-500", icon: "🏢" },
  ];

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-6xl mx-auto">

        <h1 className="text-2xl font-bold text-gray-800 mb-1">Reports & Analytics</h1>
        <p className="text-gray-500 text-sm mb-6">Real-time platform data from your database</p>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-600 px-4 py-3 rounded-lg mb-5 text-sm">
            ⚠️ {error}
          </div>
        )}

        {/* STAT CARDS */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-8">
          {statCards.map((s, i) => (
            <div key={i} className={`bg-white rounded-xl p-5 shadow-sm border-t-4 ${s.border} text-center`}>
              <div className="text-2xl mb-1">{s.icon}</div>
              <p className={`text-3xl font-bold ${s.color}`}>{s.value}</p>
              <p className="text-gray-500 text-xs mt-1">{s.label}</p>
            </div>
          ))}
        </div>

        {/* CHARTS */}
        <div className="grid md:grid-cols-2 gap-6">

          {/* BAR CHART */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
            <h2 className="font-bold text-gray-700 mb-4">Platform Overview</h2>
            {barData.every(d => d.value === 0) ? (
              <div className="text-center py-12 text-gray-400">No data yet</div>
            ) : (
              <ResponsiveContainer width="100%" height={250}>
                <BarChart data={barData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="name" tick={{ fontSize: 11 }} />
                  <YAxis allowDecimals={false} />
                  <Tooltip />
                  <Bar dataKey="value" fill="#0f766e" radius={[6, 6, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>

          {/* PIE CHART */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
            <h2 className="font-bold text-gray-700 mb-4">User Distribution</h2>
            {pieData.length === 0 ? (
              <div className="text-center py-12 text-gray-400">No users yet</div>
            ) : (
              <ResponsiveContainer width="100%" height={250}>
                <PieChart>
                  <Pie data={pieData} cx="50%" cy="50%" outerRadius={90}
                    dataKey="value" label={({ name, value }) => `${name}: ${value}`}>
                    {pieData.map((_, i) => (
                      <Cell key={i} fill={COLORS[i % COLORS.length]} />
                    ))}
                  </Pie>
                  <Legend />
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
            )}
          </div>

        </div>

        {/* SUMMARY TABLE */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 mt-6">
          <div className="p-5 border-b border-gray-100">
            <h2 className="font-bold text-gray-700">Summary</h2>
          </div>
          <table className="w-full text-sm">
            <thead className="bg-gray-50">
              <tr>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Metric</th>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Count</th>
                <th className="text-left px-5 py-3 text-gray-500 font-medium">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {statCards.map((s, i) => (
                <tr key={i} className="hover:bg-gray-50">
                  <td className="px-5 py-3 font-medium text-gray-700">{s.icon} {s.label}</td>
                  <td className={`px-5 py-3 font-bold ${s.color}`}>{s.value}</td>
                  <td className="px-5 py-3">
                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${
                      s.value > 0 ? "bg-green-100 text-green-700" : "bg-gray-100 text-gray-500"
                    }`}>
                      {s.value > 0 ? "Active" : "Empty"}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

      </div>
    </div>
  );
};

export default Reports;
